-- SIGHI Food List -> PostgreSQL staging import
-- Source: SIGHI Lebensmittel-Verträglichkeitsliste DE, Stand 2024-08-29
-- Extracted from pages 4-36 of the user-provided PDF.
--
-- IMPORTANT:
-- This script intentionally imports into a STAGING table first.
-- The original SIGHI score (0/1/2/3/?/-), H/H!, A, L, B markers and notes are preserved.
-- Do not map directly into a simpler safe/limited/unsafe enum without reviewing the loss of detail.
--
-- Suggested app mapping (stored only as text for review):
--   0 -> safe
--   1 -> limited
--   2 -> unsafe
--   3 -> unsafe
--   ?/- -> unknown
--
-- You can run the entire file in pgAdmin Query Tool.

BEGIN;

CREATE TABLE IF NOT EXISTS sighi_food_import (
    id BIGSERIAL PRIMARY KEY,
    source_page INTEGER NOT NULL,
    category TEXT,
    sighi_histamine_score TEXT NOT NULL
        CHECK (sighi_histamine_score IN ('0', '1', '2', '3', '?', '-')),
    histamine_rich_marker TEXT,
    other_amines_marker TEXT,
    liberator_marker TEXT,
    blocker_marker TEXT,
    designation_de TEXT NOT NULL,
    remarks_de TEXT,
    app_rating_suggestion TEXT NOT NULL
        CHECK (app_rating_suggestion IN ('safe', 'limited', 'unsafe', 'unknown')),
    source_name TEXT NOT NULL DEFAULT 'SIGHI',
    source_date DATE NOT NULL DEFAULT DATE '2024-08-29'
);

-- Makes the script safely repeatable for this source/version.
DELETE FROM sighi_food_import
WHERE source_name = 'SIGHI'
  AND source_date = DATE '2024-08-29';

INSERT INTO sighi_food_import (
